hype_words = ['ultimate', 'unlock', 'secret', 'amazing', 'discover', 'supercharge', 'essential', 'comprehensive', 'game-changing']

print("slug | T_len | D_len | flags")
print("-" * 100)
for slug, title, desc in proposals:
    tlen = len(title)
    dlen = len(desc)
    flags = []
    if tlen < 50:
        flags.append(f"T_SHORT={tlen}")
    if tlen > 60:
        flags.append(f"T_LONG={tlen}")
    if dlen < 120:
        flags.append(f"D_SHORT={dlen}")
    if dlen > 155:
        flags.append(f"D_LONG={dlen}")
    for hw in hype_words:
        if hw in (title + desc).lower():
            flags.append(f"HYPE:{hw}")
    for ch in ['—', '–']:
        if ch in title or ch in desc:
            flags.append(f"DASH:U+{ord(ch):04X}")
    if title.lower() in desc.lower():
        flags.append("TITLE_IN_DESC")
    status = " | ".join(flags) if flags else "OK"
    print(f"{slug[:52]:<52} T={tlen:<3} D={dlen:<3} {status}")

# Check uniqueness of titles
titles = [t for (_, t, _) in proposals]
seen = {}
for i, (slug, title, desc) in enumerate(proposals):
    if title in seen:
        print(f"DUPLICATE_TITLE: row {seen[title]} and row {i}: '{title}'")
    seen[title] = i
